#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int minimumEffort(vector<vector<int>>& heights) {
        int m = heights.size();
        int n = heights[0].size();
        const int INF = 1e9;
        vector<vector<int>> effort(m, vector<int>(n, INF));
        effort[0][0] = 0;
        using T = tuple<int,int,int>; // effort, x, y
        priority_queue<T, vector<T>, greater<T>> pq;
        pq.emplace(0,0,0);
        int dirs[4][2] = {{1,0},{-1,0},{0,1},{0,-1}};
        while(!pq.empty()){
            auto _tmp_binding_0 = pq.top(); auto cur = std::get<0>(_tmp_binding_0); auto x = std::get<1>(_tmp_binding_0); auto y = std::get<2>(_tmp_binding_0); pq.pop();
            if (cur != effort[x][y]) continue;
            if (x==m-1 && y==n-1) return cur;
            for (auto &d: dirs){
                int nx = x + d[0];
                int ny = y + d[1];
                if (nx<0||nx>=m||ny<0||ny>=n) continue;
                int diff = abs(heights[x][y] - heights[nx][ny]);
                int nxt = max(cur, diff);
                if (nxt < effort[nx][ny]){
                    effort[nx][ny] = nxt;
                    pq.emplace(nxt, nx, ny);
                }
            }
        }
        return effort[m-1][n-1];
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m,n;
    if(!(cin>>m>>n)) return 0;
    int k; cin>>k; // k = m*n
    vector<int> vals(k);
    for(int i=0;i<k;i++) cin>>vals[i];
    vector<vector<int>> heights(m, vector<int>(n));
    for(int i=0;i<m;i++){
        for(int j=0;j<n;j++){
            heights[i][j] = vals[i*n + j];
        }
    }
    Solution sol;
    int ans = sol.minimumEffort(heights);
    cout<<ans<<"\n";
    return 0;
}
